function matchOrder(name, ordersData) {
  if (!ordersData || !ordersData.orders || ordersData.orders.length === 0) return null;
  if (!name) return null;
  const n = name.toLowerCase().trim();
  // 精确匹配
  for (const o of ordersData.orders) {
    if ((o.customer || '').toLowerCase().trim() === n) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
  }
  // 模糊匹配：客户名包含公司名或反之
  for (const o of ordersData.orders) {
    const cn = (o.customer || '').toLowerCase().trim();
    if (!cn) continue;
    if (n.includes(cn) || cn.includes(n)) return { matched: true, status: o.status, paidAt: o.orderDate, orderNo: o.orderNo };
  }
  return null;
}

function bucketFilter(client) {
  const d = client.lastCustomerMsgDays;
  const g = client.grade;
  const hasOrder = !!client.orderMatched;
  const msgCount = client.realMsgs || 0;
  // 桶 2：有任一活跃信号
  if (d == null || d === '-') return 1; // 无客户消息 → 桶1
  if (typeof d === 'number' && d < 60) return 2;
  if (g === 'A' || g === 'S') return 2;
  if (hasOrder) return 2;
  if (msgCount >= 10) return 2;
  // 其余 → 桶 1
  return 1;
}

// ── 加载订单数据 ──
let ordersData = null;
const ordersPath = path.join(__dirname, '..', 'data', 'orders_latest.json');
if (fs.existsSync(ordersPath)) {
  try { ordersData = JSON.parse(fs.readFileSync(ordersPath, 'utf8')); } catch (e) {}
}
if (ordersData) {
  console.log('已加载订单数据: ' + (ordersData.total || ordersData.orders?.length || 0) + ' 条');
}

// ── 主循环 ──
const candidates = allConversations;
console.log('处理全部 ' + candidates.length + ' 个客户...\n');

const enhanced = [];
for (const c of candidates) {
  // 平台机器人/非客户实体 → D级
  if (c.name === 'Assistant Eva') continue; // 平台机器人
  const fid = c.cid ? c.cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200) + '.json' : '';
  const fp = path.join(chatDir, fid);

  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
  let hasPrice = false, hasSample = false, hasQuantity = false;
  let latestOurDate = '', latestCustDate = '';
  let lastCustomerMsgDays = 9999;
  let fullCustText = '', fullConvText = '';
  let allMsgs = [];

  if (fs.existsSync(fp)) {
    try {
      const data = JSON.parse(fs.readFileSync(fp, 'utf8'));
      allMsgs = data.messages || [];
      msgCount = allMsgs.length;

      for (const m of allMsgs) {
        const msg = m.message || m;
        const uid = msg.sender && msg.sender.uid || '';
        const text = getText(msg.content, msg.searchableContent);
        const date = msg.createAt || '';
        if (isSys(msg.content)) { sysMsgs++; continue; }

        if (uid === OUR_UID) {
          ourMsgs++;
          if (date > latestOurDate) latestOurDate = date;
          if (text.trim()) fullConvText += text + ' | ';
        } else if (uid) {
