// ── 主循环 ──
const candidates = allConversations;
console.log('处理全部 ' + candidates.length + ' 个客户...\n');

const enhanced = [];
for (const c of candidates) {
  // 平台机器人/非客户实体 → D级
  if (c.name === 'Assistant Eva') continue; // 平台机器人
  const fid = c.cid ? c.cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200) + '.json' : '';
  const fp = path.join(chatDir, fid);

  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
  let hasPrice = false, hasSample = false, hasQuantity = false;
  let latestOurDate = '', latestCustDate = '';
  let lastCustomerMsgDays = 9999;
  let fullCustText = '', fullConvText = '';
  let allMsgs = [];

  if (fs.existsSync(fp)) {
    try {
      const data = JSON.parse(fs.readFileSync(fp, 'utf8'));
      allMsgs = data.messages || [];
      msgCount = allMsgs.length;

      for (const m of allMsgs) {
        const msg = m.message || m;
        const uid = msg.sender && msg.sender.uid || '';
        const text = getText(msg.content, msg.searchableContent);
        const date = msg.createAt || '';
        if (isSys(msg.content)) { sysMsgs++; continue; }

        if (uid === OUR_UID) {
          ourMsgs++;
          if (date > latestOurDate) latestOurDate = date;
          if (text.trim()) fullConvText += text + ' | ';
        } else if (uid) {
          customerMsgs++;
          if (date > latestCustDate) latestCustDate = date;
          if (text.trim()) { fullCustText += text + ' | '; fullConvText += text + ' | '; }
          if (date) lastCustomerMsgDays = Math.min(lastCustomerMsgDays, Math.floor((NOW - new Date(date).getTime()) / DAY));
        }

        // 仅保留 grade 判定所需的三个信号（生命周期/行动判定不用）
        const lc = text.toLowerCase();
        if (!hasPrice && /(price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
        if (!hasSample && /(sample|样品)/.test(lc)) hasSample = true;
        if (!hasQuantity && /(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
      }
    } catch (e) { /* skip corrupt */ }
  }

  const realMsgs = customerMsgs + ourMsgs;
  const country = c.complianceCountryCode || c.country || '';
  const direction = lastCustomerMsgDays !== 9999 && latestCustDate > latestOurDate ? 'to_us' : 'to_them';

  // 质量等级（脚本继续算，AI 可覆盖）
  const ql = determineQuality({
    realMsgs, customerMsgs, ourMsgs, hasPrice, hasSample, hasQuantity, lastCustomerMsgDays
  }, fullCustText, fullConvText);

  // 订单匹配
  const orderMatched = matchOrder(c.name, ordersData);

  // 对话片段
  const snippet = extractConversationSnippet(allMsgs, 12);

  const obj = {
    name: c.name || '(未知)',
    country,
    countryCN: countryCN(country),
    cid: c.cid,
    grade: ql.grade,
    gradeReason: ql.reason,
    totalMsgs: msgCount,
    customerMsgs,
    ourMsgs,
    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? null : lastCustomerMsgDays,
    direction,
    order: orderMatched,
    snippet,
    // 临时字段（供分桶+后续使用）
    realMsgs,
    fullCustText,
    fullConvText,
  };

  obj.bucket = bucketFilter(obj);
  enhanced.push(obj);
}

