const fs = require('fs');
const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));
const s3 = JSON.parse(fs.readFileSync('./data/s3_ai_judgments.json', 'utf8'));

// Build lookup
const s3Map = {};
s3.forEach(r => s3Map[r.cid] = r);

// Signal words
const approvalWords = /wait|check with|discuss with|商量|确认一下|审批|partner|team|manager|let me|i'll.{0,10}(check|ask|confirm|discuss)|我会.{0,5}(问|确认|商量|查)/i;
const negativeWords = /disappointed|not what I expected|not happy|problem with quality|issue with|doesn't match|wrong|退款|退货|refund|not.{0,5}(good|right|correct)|damaged|missing|defect|poor|bad quality/i;

const edgeCases = [];

s2.forEach(c => {
  const r = s3Map[c.cid];
  if (!r) return;

  const snippetText = (c.snippet || []).join(' ');
  const snippetLen = snippetText.length;
  const d = c.lastCustomerMsgDays;
  const stage = r.stage;
  const grade = r.grade;
  const priority = r.priority;

  // Layer 1: edge scope — 14-90d silence & non-terminal, OR S/A any silence
  const inEdgeScope = (d != null && d >= 14 && d <= 90 && stage !== '搁置' && stage !== '未成交' && stage !== '售后') 
    || (grade === 'S' || grade === 'A');

  if (!inEdgeScope) return;

  // Layer 2: denoise — strip D, 未成交, >90d (keep S/A)
  if (grade === 'D') return;
  if (stage === '未成交') return;
  if (d != null && d > 90 && grade !== 'S' && grade !== 'A') return;

  // Layer 3: readability
  const hasApproval = approvalWords.test(snippetText);
  const hasNegative = negativeWords.test(snippetText);
  const readable = snippetLen >= 500 || grade === 'S' || grade === 'A' || hasApproval || hasNegative;
  if (!readable) return;

  // Layer 4: categorize
  let category = '';
  if ((grade === 'S' || grade === 'A') && stage === '搁置' && d >= 30 && d <= 90) {
    category = '高价值搁置';
  } else if (stage !== '搁置' && d >= 30 && d <= 90) {
    category = '活跃待确认';
  } else if (stage === '待付款' && d > 14) {
    category = '付款卡住';
  } else if (hasNegative) {
    category = '负面信号';
  } else if (hasApproval && d >= 14 && d <= 30) {
    category = '审批信号';
  } else if (grade === 'S' || grade === 'A') {
    category = '高价值复核';
  } else {
    category = '其他边缘';
  }

  edgeCases.push({
    name: c.name,
    cid: c.cid,
    country: c.country,
    grade,
    stage,
    priority,
    silenceDays: d,
    totalMsgs: c.totalMsgs,
    snippetLen,
    category,
    hasApproval,
    hasNegative,
    reason: r.reason,
    snippetPreview: snippetText.substring(0, 300)
  });
});

// Sort by category then grade
const catOrder = ['高价值搁置','活跃待确认','付款卡住','负面信号','审批信号','高价值复核','其他边缘'];
