const fs = require('fs');
const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));
const edge = JSON.parse(fs.readFileSync('./data/edge_cases_ai_review_2026-05-15.json', 'utf8'));

// Build lookup from s2
const s2Map = {};
s2.forEach(c => s2Map[c.cid] = c);

// Enrich edge cases with full snippet
const enriched = edge.map(e => {
  const c = s2Map[e.cid];
  const fullSnippet = c ? (c.snippet || []).join('\n') : '';
  return { ...e, fullSnippet, snippetLen: fullSnippet.length };
});

// Split into priority batches
const critical = enriched.filter(e => ['付款卡住','负面信号'].includes(e.category));
const highPriority = enriched.filter(e => e.category === '审批信号');
const activeReview = enriched.filter(e => ['活跃待确认','优先级可疑'].includes(e.category));
const highValueSilent = enriched.filter(e => e.category === '高价值搁置');

console.log('Batch 1 (critical):', critical.length);
console.log('Batch 2 (approval signals):', highPriority.length);
console.log('Batch 3 (active review):', activeReview.length);
console.log('Batch 4 (high-value silent):', highValueSilent.length);

// Write batches
fs.writeFileSync('./data/ai_review_batch1_critical.json', JSON.stringify(critical, null, 2));
fs.writeFileSync('./data/ai_review_batch2_approval.json', JSON.stringify(highPriority, null, 2));
fs.writeFileSync('./data/ai_review_batch3_active.json', JSON.stringify(activeReview, null, 2));
fs.writeFileSync('./data/ai_review_batch4_silent.json', JSON.stringify(highValueSilent, null, 2));

// For Batch 4, do fast pre-scan: flag ones with re-engagement hooks
console.log('');
console.log('=== Batch 4 fast pre-scan (looking for re-engagement hooks) ===');
const reengageHooks = /(?:let me|i'll|i will|我会|先看|商量|discuss|check|确认|下周|next week|soon|尽快|ASAP|urgent|ready.{0,10}order|准备.{0,5}订|want.{0,10}buy|想买|coming back|回来|still interest|还在.{0,5}兴趣)/i;
highValueSilent.forEach((e,i) => {
  const hasHook = reengageHooks.test(e.fullSnippet);
  if (hasHook) {
    console.log((i+1) + '. [HOOK] ' + e.name + ' | ' + e.country + ' | sil=' + e.silenceDays + 'd | chars=' + e.snippetLen);
    // Find the hook sentence
    const match = e.fullSnippet.match(/(?:let me|i'll|i will|我会|先看|商量|discuss|check|确认|下周|next week|soon|尽快|ASAP|urgent|ready.{0,10}order|准备.{0,5}订|want.{0,10}buy|想买|coming back|回来|still interest|还在.{0,5}兴趣)/i);
    if (match) console.log('   Hook: ...' + e.fullSnippet.substring(Math.max(0, match.index-30), match.index + match[0].length + 50) + '...');
  }
});
