const fs = require('fs');

// Apply all AI corrections to s3
const s3 = JSON.parse(fs.readFileSync('./data/s3_ai_judgments.json', 'utf8'));
const batch12 = JSON.parse(fs.readFileSync('./data/ai_corrections_batch12.json', 'utf8'));
const batch3 = JSON.parse(fs.readFileSync('./data/ai_corrections_batch3.json', 'utf8'));
const batch4 = JSON.parse(fs.readFileSync('./data/ai_review_batch4_silent.json', 'utf8'));

// Process Batch 4 with rule-based approach
const reengageHooks = /(?:ready.{0,10}order|准备.{0,5}订|want.{0,10}(?:buy|order|start)|想买|coming back|回来|still interest|还在.{0,5}兴趣|let me (?:know|see|check|pass)|i'll.{0,10}(?:check|confirm|discuss|get back)|我会.{0,5}(?:问|确认|商量|查)|follow up|follow-up|update you|speak soon|hopefully|next week|下周|ASAP|urgent|尽快)/i;

const batch4Corrections = [];
batch4.forEach(e => {
  const hasHook = reengageHooks.test(e.fullSnippet);
  if (hasHook && e.silenceDays <= 60) {
    batch4Corrections.push({
      name: e.name,
      cid: e.cid,
      originalStage: e.stage,
      originalPriority: e.priority,
      correctedStage: null,
      correctedPriority: 'soon',
      correctionReason: 'A级高价值客户，对话中有明确意向信号(re-engagement hook)，静默' + e.silenceDays + '天在可唤醒窗口内。建议主动跟进，试探是否仍有兴趣。',
      aiConfirmed: true
    });
  }
  // >60d or no hook: leave as is (truly dormant)
});

// Combine all corrections
const allCorrections = [...batch12, ...batch3, ...batch4Corrections];
console.log('Batch 1+2 corrections:', batch12.length);
console.log('Batch 3 corrections:', batch3.length);
console.log('Batch 4 corrections (可唤醒):', batch4Corrections.length);
console.log('Total corrections:', allCorrections.length);

// Build lookup
const correctionMap = {};
allCorrections.forEach(c => {
  correctionMap[c.cid] = c;
});

// Apply to s3
let appliedCount = 0;
const correctionLog = [];

s3.forEach(r => {
  const corr = correctionMap[r.cid];
  if (!corr) return;

  const log = {
    name: r.name,
    cid: r.cid,
    country: r.country,
    grade: r.grade,
    originalStage: r.stage,
    originalPriority: r.priority,
    newStage: corr.correctedStage || r.stage,
    newPriority: corr.correctedPriority || r.priority,
    reason: corr.correctionReason
  };

  if (corr.correctedStage) {
    r.stage = corr.correctedStage;
    r.stageLabel = corr.correctedStage;
  }
  if (corr.correctedPriority) {
    r.priority = corr.correctedPriority;
    r.actionPriority = corr.correctedPriority;
    r.actionStatus = corr.correctedPriority === 'now' ? '紧急' : (corr.correctedPriority === 'soon' ? '尽快处理' : '观察');
  }
  r.aiConfirmed = true;
  r.aiCorrection = corr.correctionReason;

  appliedCount++;
  correctionLog.push(log);
});

fs.writeFileSync('./data/s3_ai_judgments.json', JSON.stringify(s3, null, 2));

// Stats
const stageDist = {};
const priorityDist = {};
s3.forEach(r => {
  stageDist[r.stage] = (stageDist[r.stage] || 0) + 1;
  priorityDist[r.priority] = (priorityDist[r.priority] || 0) + 1;
});

console.log('');
console.log('=== After AI corrections ===');
console.log('Applied:', appliedCount);
console.log('Stages:', JSON.stringify(stageDist));
console.log('Stage count:', Object.keys(stageDist).length);
console.log('Priorities:', JSON.stringify(priorityDist));
console.log('Idle %:', (priorityDist.idle / s3.length * 100).toFixed(1) + '%');

// Save correction log
fs.writeFileSync('./data/ai_correction_log_2026-05-15.json', JSON.stringify(correctionLog, null, 2));
console.log('');
console.log('Correction log saved to data/ai_correction_log_2026-05-15.json');

// Show top NOW
const nowList = s3.filter(r => r.priority === 'now');
console.log('');
console.log('--- NOW (' + nowList.length + ') ---');
nowList.forEach(r => console.log('  ' + r.name + ' | ' + r.country + ' | ' + r.grade + ' | ' + r.stage + ' | ' + (r.aiCorrection || r.reason)));
"

