const fs = require('fs');
const log = JSON.parse(fs.readFileSync('./data/ai_correction_log_2026-05-15.json', 'utf8'));

// Pattern analysis
const patterns = {};

log.forEach(c => {
  const r = c.reason.toLowerCase();

  if (/supplier.{0,20}dropped.{0,10}ball|承诺|promised|waiting on (us|supplier|our)|never sent|never followed|never delivered/i.test(r)) {
    patterns['我方承诺未兑现'] = (patterns['我方承诺未兑现']||0)+1;
  }
  if (/stage.{0,10}(error|inflat|overstat|wrong)|谈判中.{0,10}需求探索|需求探索.{0,10}谈判中|报价已发.{0,10}(no quote|never sent)/i.test(r)) {
    patterns['阶段判定膨胀'] = (patterns['阶段判定膨胀']||0)+1;
  }
  if (/已签收.{0,10}(no |not |wrong|error|inflat)|no order.{0,10}(exist|at all)|hasApproval=false/i.test(r)) {
    patterns['已签收误判'] = (patterns['已签收误判']||0)+1;
  }
  if (/待付款.{0,10}(no |not |wrong|error)|not payment/i.test(r)) {
    patterns['待付款误判'] = (patterns['待付款误判']||0)+1;
  }
  if (/template|wrong name|wrong market|称呼|addressed/i.test(r)) {
    patterns['模板/称呼错误'] = (patterns['模板/称呼错误']||0)+1;
  }
  if (/off-putting|privacy|sensitive|inappropriate/i.test(r)) {
    patterns['沟通方式不当'] = (patterns['沟通方式不当']||0)+1;
  }
  if (/negative|dissatisf|complaint|failed to deliver/i.test(r)) {
    patterns['负面信号遗漏'] = (patterns['负面信号遗漏']||0)+1;
  }
});

console.log('=== Systemic patterns (>=3 occurrences → fix rules) ===');
Object.entries(patterns).sort((a,b) => b[1]-a[1]).forEach(([k,v]) => {
  console.log((v>=3?'FIX':'note') + ': ' + k + ': ' + v + '次');
});

// Write correction markdown
let md = '# AI 修正日志 — 2026-05-15\\n\\n';
md += '## 概要\\n\\n';
md += '- 基线判定：465 人，10 阶段\\n';
md += '- 边缘案例筛选：71 人进入 AI 审查\\n';
md += '- AI 修正：33 人（7.1%）\\n';
md += '- 修正后 NOW：5 → 13 人\\n';
md += '- 修正后 idle：79.1% → 75.5%\\n\\n';

md += '## 修正明细\\n\\n';

const categories = {};
log.forEach(c => {
  const r = c.reason.toLowerCase();
  let cat = '其他';
  if (/supplier.{0,20}dropped|承诺|promised|waiting on (us|supplier)/i.test(r)) cat = '我方承诺未兑现';
  else if (/stage.{0,10}(error|inflat|wrong)/i.test(r)) cat = '阶段判定修正';
  else if (/已签收.*no order|no order.*exist|hasApproval=false/i.test(r)) cat = '已签收误判修正';
  else if (/negative|dissatisf|failed to deliver/i.test(r)) cat = '负面信号遗漏';
  else if (/template|wrong name|称呼/i.test(r)) cat = '模板错误修正';
  else if (/off-putting|privacy|inappropriate/i.test(r)) cat = '沟通修正';
  else if (/可唤醒|re-engagement/i.test(r)) cat = '高价值可唤醒';
  else cat = '优先级修正';
  categories[cat] = (categories[cat]||0)+1;
});

Object.entries(categories).sort((a,b)=>b[1]-a[1]).forEach(([k,v]) => {
  md += '### ' + k + '（' + v + '人）\\n\\n';
  log.filter(c => {
    const r = c.reason.toLowerCase();
    if (k==='我方承诺未兑现') return /supplier.{0,20}dropped|承诺|promised|waiting on (us|supplier)/i.test(r);
    if (k==='阶段判定修正') return /stage.{0,10}(error|inflat|wrong)/i.test(r);
    if (k==='已签收误判修正') return /已签收.*no order|no order.*exist|hasApproval=false/i.test(r);
    if (k==='负面信号遗漏') return /negative|dissatisf|failed to deliver/i.test(r);
    if (k==='模板错误修正') return /template|wrong name|称呼/i.test(r);
    if (k==='沟通修正') return /off-putting|privacy|inappropriate/i.test(r);
    if (k==='高价值可唤醒') return /可唤醒|re-engagement/i.test(r);
    return c.reason.toLowerCase().includes(k.slice(0,4));
  }).forEach(c => {
    md += '| ' + c.name + ' | ' + c.country + ' | ' + c.grade + ' | ' + c.originalStage + ' → ' + c.newStage + ' | ' + c.originalPriority + ' → ' + c.newPriority + ' | ' + c.reason.substring(0, 100) + ' |\\n';
  });
  md += '\\n';
});

md += '## 系统性模式\\n\\n';
md += '| 模式 | 次数 | 建议修复 |\\n';
md += '|------|------|----------|\\n';
Object.entries(patterns).sort((a,b)=>b[1]-a[1]).forEach(([k,v]) => {
  const fix = v>=3 ? '修 ai_classify.js 规则' : '观察';
  md += '| ' + k + ' | ' + v + ' | ' + fix + ' |\\n';
});

md += '\\n## 学习闭环\\n\\n';
const fixItems = Object.entries(patterns).filter(([k,v])=>v>=3);
if (fixItems.length > 0) {
  md += '以下模式 ≥3 次，应修脚本规则：\\n\\n';
  fixItems.forEach(([k,v]) => {
    if (k === '我方承诺未兑现') md += '- **' + k + '**（' + v + '次）：在 ai_classify.js 中添加承诺检测：我方最后一条消息含 \"will send/check/reply/update\" + 14d+ 静默 → 升级 priority 为 now\\n';
    if (k === '阶段判定膨胀') md += '- **' + k + '**（' + v + '次）：谈判中判定加硬门槛：至少 6 条消息 + 有价格讨论 + 有来回互动。报价已发判定加硬门槛：必须确实有报价内容\\n';
    if (k === '已签收误判') md += '- **' + k + '**（' + v + '次）：已签收判定需订单匹配确认，仅有 hasReceived 关键词不够\\n';
    if (k === '待付款误判') md += '- **' + k + '**（' + v + '次）：待付款判定需订单状态确认为待收款，仅有 hasPayment 关键词不够\\n';
  });
}

fs.writeFileSync('./output/ai_corrections_2026-05-15.md', md);
console.log('');
console.log('Written to output/ai_corrections_2026-05-15.md');
"

