    if (k === '待付款误判') md += '- **' + k + '**（' + v + '次）：待付款判定需订单状态确认为待收款，仅有 hasPayment 关键词不够\\n';
  });
}

fs.writeFileSync('./output/ai_corrections_2026-05-15.md', md);
