// Build lookup
const s3Map = {};
s3.forEach(r => s3Map[r.cid] = r);

// Only apply corrections that are still needed (rules may have fixed some)
let applied = 0;
const skipped = [];

log.forEach(c => {
  const r = s3Map[c.cid];
  if (!r) return;

  // Check if the new baseline already matches the correction
  let needsStageFix = c.originalStage !== c.newStage && r.stage === c.originalStage;
  let needsPriorityFix = c.originalPriority !== c.newPriority && r.priority === c.originalPriority;

  // If the new baseline already fixed it, skip
  if (!needsStageFix && !needsPriorityFix) {
    skipped.push(c.name + ' (already fixed by rules)');
    // Still mark as aiConfirmed
    r.aiConfirmed = true;
    return;
  }

  // Apply remaining corrections
  if (needsStageFix) {
    r.stage = c.newStage;
    r.stageLabel = c.newStage;
  }
  if (needsPriorityFix) {
    r.priority = c.newPriority;
    r.actionPriority = c.newPriority;
    r.actionStatus = c.newPriority === 'now' ? '紧急' : (c.newPriority === 'soon' ? '尽快处理' : '观察');
  }
  r.aiConfirmed = true;
  r.aiCorrection = c.reason;
  applied++;
});

// Add batch 4 corrections for high-value silent (these aren't in the log yet)
// Re-process batch 4
const batch4 = JSON.parse(fs.readFileSync('./data/ai_review_batch4_silent.json', 'utf8'));
