let batch4Applied = 0;
batch4.forEach(e => {
  const r = s3Map[e.cid];
  if (!r) return;
  const hasHook = reengageHooks.test(e.fullSnippet);
  if (hasHook && e.silenceDays <= 60 && r.priority === 'idle') {
    r.priority = 'soon';
    r.actionPriority = 'soon';
    r.actionStatus = '尽快处理';
    r.aiConfirmed = true;
    r.aiCorrection = 'A级高价值客户，对话中有明确意向信号，静默' + e.silenceDays + '天在可唤醒窗口内';
    batch4Applied++;
  }
});

fs.writeFileSync('./data/s3_ai_judgments.json', JSON.stringify(s3, null, 2));

// Stats
const stageDist = {}, priorityDist = {};
s3.forEach(r => {
  stageDist[r.stage] = (stageDist[r.stage]||0)+1;
  priorityDist[r.priority] = (priorityDist[r.priority]||0)+1;
});

console.log('AI corrections re-applied:', applied);
console.log('Batch 4 (可唤醒) applied:', batch4Applied);
console.log('Skipped (already fixed by rules):', skipped.length);
console.log('');
console.log('Stages:', JSON.stringify(stageDist));
console.log('Priorities:', JSON.stringify(priorityDist));
console.log('NOW:', priorityDist.now, '| SOON:', priorityDist.soon, '| IDLE:', priorityDist.idle);
console.log('Idle %:', (priorityDist.idle/s3.length*100).toFixed(1)+'%');
console.log('');
if (skipped.length > 0) {
  console.log('Skipped:', skipped.join(', '));
}
"

