const fs = require('fs');
const s2 = JSON.parse(fs.readFileSync('./data/s2_ai_input.json', 'utf8'));

// Check: how many customers have >100 messages but tiny snippet?
const deep = s2.filter(c => c.totalMsgs > 100);
console.log('Customers with >100 msgs:', deep.length);
console.log('Their grade distribution:');
const gd = {};
deep.forEach(c => gd[c.grade] = (gd[c.grade]||0)+1);
console.log(JSON.stringify(gd));

// Check snippet length for deep customers
let shortSnippetDeep = deep.filter(c => (c.snippet||[]).join(' ').length < 500);
console.log('Deep customers with <500 char snippet:', shortSnippetDeep.length);
shortSnippetDeep.slice(0, 5).forEach(c => {
  console.log('  ' + c.name + ' | msgs=' + c.totalMsgs + ' | custMsgs=' + c.customerMsgs + ' | sil=' + c.lastCustomerMsgDays + 'd | grade=' + c.grade);
});

// How many to_us SHOULD there be? Check: our last msg contains promise/question
const ourPromise = /(?:i will|i'll|我会|let me|please wait|sorry|apolog|明天|tomorrow|shortly|soon|尽快|asap|check|confirm|send|reply|update).{0,50}$/i;
const pendingAction = s2.filter(c => {
  if (c.direction !== 'to_them') return false;
  if (!c.snippet || c.snippet.length === 0) return false;
  const lastMsg = c.snippet[c.snippet.length - 1] || '';
  // Our last msg is a promise, or customer's last msg is a question
  const custLastMsgs = c.snippet.filter(s => s.startsWith('[客户]'));
  const ourLastMsgs = c.snippet.filter(s => s.startsWith('[我方]'));
  const lastIsOurs = c.snippet[c.snippet.length-1].startsWith('[我方]');
  const lastIsCust = c.snippet[c.snippet.length-1].startsWith('[客户]');

  // Case 1: Customer sent last message → should be to_us
  if (lastIsCust && c.lastCustomerMsgDays <= 14) return true;

  // Case 2: We sent last message but it's a promise/question
  if (lastIsOurs && ourPromise.test(lastMsg) && c.lastCustomerMsgDays >= 5) return true;

  return false;
});

console.log('\n=== Potential to_us (pending action) ===');
console.log('Count:', pendingAction.length);
pendingAction.slice(0, 15).forEach(c => {
  const lastMsg = c.snippet[c.snippet.length-1];
  console.log(c.name + ' | sil=' + c.lastCustomerMsgDays + 'd | last: ' + lastMsg.substring(0, 100));
});
"

